'use client';

import { useEffect, useState, use } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { useAuth } from '@/contexts/auth-context';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Skeleton } from '@/components/ui/skeleton';
import { Separator } from '@/components/ui/separator';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Spinner } from '@/components/ui/spinner';
import {
  ArrowLeftIcon,
  FileTextIcon,
  UserIcon,
  BuildingIcon,
  PhoneIcon,
  EnvelopeSimpleIcon,
  MapPinIcon,
  CurrencyCircleDollarIcon,
  ClockIcon,
  CheckCircleIcon,
  XCircleIcon,
  WarningCircleIcon,
  PaperPlaneTiltIcon,
  MagnifyingGlassIcon,
  StampIcon,
  InfoIcon,
  UploadIcon,
  EyeIcon,
  ClockCounterClockwiseIcon,
} from '@phosphor-icons/react';
import type { Application, ApplicationStatus, Document, AuditLogEntry } from '@/lib/types';
import { format, formatDistanceToNow } from 'date-fns';

interface EnrichedApplication extends Application {
  applicantName: string;
  applicantEmail: string;
  reviewerName: string | null;
  reviewerEmail: string | null;
  approverName: string | null;
  approverEmail: string | null;
}

export default function ApplicationDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const router = useRouter();
  const { user, permissions } = useAuth();

  const [application, setApplication] = useState<EnrichedApplication | null>(null);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');

  // Dialog states
  const [showReviewDialog, setShowReviewDialog] = useState(false);
  const [showRequestInfoDialog, setShowRequestInfoDialog] = useState(false);
  const [showApprovalDialog, setShowApprovalDialog] = useState(false);
  const [showRejectDialog, setShowRejectDialog] = useState(false);
  const [showUploadDialog, setShowUploadDialog] = useState(false);

  // Forms states
  const [reviewNotes, setReviewNotes] = useState('');
  const [recommendation, setRecommendation] = useState<'approve' | 'reject' | ''>('');
  const [additionalInfoRequest, setAdditionalInfoRequest] = useState('');
  const [approvalNotes, setApprovalNotes] = useState('');
  const [rejectionReason, setRejectionReason] = useState('');
  const [isActionLoading, setIsActionLoading] = useState(false);
  const [actionError, setActionError] = useState('');

  // Upload states
  const [uploadFile, setUploadFile] = useState<{ name: string; type: string; size: number } | null>(null);

  useEffect(() => {
    fetchApplication();
  }, [id]);

  async function fetchApplication() {
    try {
      const response = await fetch(`/api/applications/${id}`);
      if (response.ok) {
        const data = await response.json();
        setApplication(data.application);
        setDocuments(data.documents || []);
        setAuditLog(data.auditLog || []);
      } else if (response.status === 404) {
        setError('Application not found');
      } else if (response.status === 403) {
        setError('You do not have permission to view this application');
      } else {
        setError('Failed to load application');
      }
    } catch {
      setError('Network error');
    } finally {
      setIsLoading(false);
    }
  }

  async function performAction(action: string, data: Record<string, unknown> = {}) {
    setIsActionLoading(true);
    setActionError('');

    try {
      const response = await fetch(`/api/applications/${id}/actions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, ...data }),
      });

      const result = await response.json();

      if (response.ok && result.success) {
        await fetchApplication();
        closeAllDialogs();
      } else {
        setActionError(result.error || 'Action failed');
      }
    } catch {
      setActionError('Network error');
    } finally {
      setIsActionLoading(false);
    }
  }

  async function uploadDocument() {
    if (!uploadFile) return;

    setIsActionLoading(true);
    setActionError('');

    try {
      const response = await fetch(`/api/applications/${id}/documents`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(uploadFile),
      });

      const result = await response.json();

      if (response.ok && result.success) {
        await fetchApplication();
        setShowUploadDialog(false);
        setUploadFile(null);
      } else {
        setActionError(result.error || 'Upload failed');
      }
    } catch {
      setActionError('Network error');
    } finally {
      setIsActionLoading(false);
    }
  }

  function closeAllDialogs() {
    setShowReviewDialog(false);
    setShowRequestInfoDialog(false);
    setShowApprovalDialog(false);
    setShowRejectDialog(false);
    setShowUploadDialog(false);
    setReviewNotes('');
    setRecommendation('');
    setAdditionalInfoRequest('');
    setApprovalNotes('');
    setRejectionReason('');
    setActionError('');
  }

  const getStatusBadge = (status: ApplicationStatus) => {
    const config: Record<ApplicationStatus, { variant: 'default' | 'secondary' | 'destructive' | 'outline'; label: string; className?: string }> = {
      draft: { variant: 'outline', label: 'Draft' },
      submitted: { variant: 'secondary', label: 'Submitted' },
      under_review: { variant: 'default', label: 'Under Review', className: 'bg-blue-500' },
      additional_info_required: { variant: 'outline', label: 'Additional Info Required', className: 'border-orange-500 text-orange-600' },
      reviewed: { variant: 'secondary', label: 'Reviewed - Awaiting Decision', className: 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200' },
      approved: { variant: 'default', label: 'Approved', className: 'bg-green-500' },
      rejected: { variant: 'destructive', label: 'Rejected' },
    };
    const { variant, label, className } = config[status];
    return <Badge variant={variant} className={className}>{label}</Badge>;
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-RW', {
      style: 'currency',
      currency: 'RWF',
      minimumFractionDigits: 0,
    }).format(amount);
  };

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  // Give permission according to the roles
  const canSubmit = user?.role === 'applicant' && application?.applicantId === user.id && application?.status === 'draft';
  const canStartReview = permissions?.canReviewApplications && application?.status === 'submitted';
  const canRequestInfo = permissions?.canReviewApplications && application?.reviewerId === user?.id && application?.status === 'under_review';
  const canCompleteReview = permissions?.canReviewApplications && application?.reviewerId === user?.id && application?.status === 'under_review';
  const canSubmitAdditionalInfo = user?.role === 'applicant' && application?.applicantId === user.id && application?.status === 'additional_info_required';
  const canApprove = permissions?.canApproveApplications && application?.status === 'reviewed' && application?.reviewerId !== user?.id;
  const canReject = permissions?.canApproveApplications && application?.status === 'reviewed' && application?.reviewerId !== user?.id;
  const canUploadDocuments = permissions?.canUploadDocuments && application?.applicantId === user?.id && ['draft', 'submitted', 'additional_info_required'].includes(application?.status || '');

  // Check if current user is the reviewer 
  const isReviewer = application?.reviewerId === user?.id;
  const showMakerCheckerWarning = permissions?.canApproveApplications && application?.status === 'reviewed' && isReviewer;

  if (isLoading) {
    return (
      <div className="space-y-6">
        <div className="flex items-center gap-4">
          <Skeleton className="h-8 w-8" />
          <div className="space-y-2">
            <Skeleton className="h-6 w-48" />
            <Skeleton className="h-4 w-32" />
          </div>
        </div>
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center py-12">
        <WarningCircleIcon className="h-12 w-12 text-destructive mb-4" />
        <h1 className="text-xl font-bold">Error</h1>
        <p className="text-muted-foreground mt-2">{error}</p>
        <Link href="/applications" className="mt-4">
          <Button>Back to Applications</Button>
        </Link>
      </div>
    );
  }

  if (!application) {
    return null;
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex items-start gap-4">
          <Link href="/applications">
            <Button variant="ghost" size="sm" className="gap-2">
              <ArrowLeftIcon size={16} />
              Back
            </Button>
          </Link>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-bold tracking-tight">{application.bankName}</h1>
              {getStatusBadge(application.status)}
            </div>
            <p className="text-muted-foreground font-mono">{application.referenceNumber}</p>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex flex-wrap gap-2">
          {canSubmit && (
            <Button onClick={() => performAction('submit')} className="gap-2">
              <PaperPlaneTiltIcon size={16} />
              Submit Application
            </Button>
          )}
          {canStartReview && (
            <Button onClick={() => performAction('start_review')} className="gap-2">
              <MagnifyingGlassIcon size={16} />
              Start Review
            </Button>
          )}
          {canRequestInfo && (
            <Button variant="outline" onClick={() => setShowRequestInfoDialog(true)} className="gap-2">
              <InfoIcon size={16} />
              Request Info
            </Button>
          )}
          {canCompleteReview && (
            <Button onClick={() => setShowReviewDialog(true)} className="gap-2">
              <CheckCircleIcon size={16} />
              Complete Review
            </Button>
          )}
          {canSubmitAdditionalInfo && (
            <Button onClick={() => performAction('submit_additional_info')} className="gap-2">
              <PaperPlaneTiltIcon size={16} />
              Submit Additional Info
            </Button>
          )}
          {canApprove && (
            <Button onClick={() => setShowApprovalDialog(true)} className="gap-2 bg-green-600 hover:bg-green-700">
              <StampIcon size={16} />
              Approve
            </Button>
          )}
          {canReject && (
            <Button variant="destructive" onClick={() => setShowRejectDialog(true)} className="gap-2">
              <XCircleIcon size={16} />
              Reject
            </Button>
          )}
          {canUploadDocuments && (
            <Button variant="outline" onClick={() => setShowUploadDialog(true)} className="gap-2">
              <UploadIcon size={16} />
              Upload Document
            </Button>
          )}
        </div>
      </div>

      {/* Maker-Checker Warning */}
      {showMakerCheckerWarning && (
        <Alert variant="destructive">
          <WarningCircleIcon className="h-4 w-4" />
          <AlertTitle>Maker-Checker Restriction</AlertTitle>
          <AlertDescription>
            You reviewed this application and cannot make the final approval decision.
            Another approver must make the final decision.
          </AlertDescription>
        </Alert>
      )}

      {/* Additional Info Required Alert */}
      {application.status === 'additional_info_required' && application.additionalInfoRequest && (
        <Alert>
          <InfoIcon className="h-4 w-4" />
          <AlertTitle>Additional Information Required</AlertTitle>
          <AlertDescription>{application.additionalInfoRequest}</AlertDescription>
        </Alert>
      )}

      {/* Final Decision Alert */}
      {application.status === 'approved' && (
        <Alert className="border-green-500 bg-green-50 dark:bg-green-950/30">
          <CheckCircleIcon className="h-4 w-4 text-green-600" />
          <AlertTitle className="text-green-800 dark:text-green-200">Application Approved</AlertTitle>
          <AlertDescription className="text-green-700 dark:text-green-300">
            {application.approvalNotes || 'This application has been approved.'}
            <div className="mt-2 text-sm">
              Approved by: {application.approverName} on {application.decidedAt && format(new Date(application.decidedAt), 'PPP')}
            </div>
          </AlertDescription>
        </Alert>
      )}

      {application.status === 'rejected' && (
        <Alert variant="destructive">
          <XCircleIcon className="h-4 w-4" />
          <AlertTitle>Application Rejected</AlertTitle>
          <AlertDescription>
            {application.rejectionReason}
            <div className="mt-2 text-sm">
              Rejected by: {application.approverName} on {application.decidedAt && format(new Date(application.decidedAt), 'PPP')}
            </div>
          </AlertDescription>
        </Alert>
      )}

      <div className="grid gap-6 lg:grid-cols-3">
        {/* Main Content */}
        <div className="lg:col-span-2 space-y-6">
          {/* Bank Information */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <BuildingIcon size={20} />
                Bank Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <Label className="text-muted-foreground">Bank Name</Label>
                  <p className="font-medium">{application.bankName}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Bank Type</Label>
                  <p className="font-medium capitalize">{application.bankType}</p>
                </div>
              </div>
              <div>
                <Label className="text-muted-foreground flex items-center gap-1">
                  <MapPinIcon size={14} /> Business Address
                </Label>
                <p className="font-medium">{application.businessAddress}</p>
              </div>
              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <Label className="text-muted-foreground flex items-center gap-1">
                    <EnvelopeSimpleIcon size={14} /> Contact Email
                  </Label>
                  <p className="font-medium">{application.contactEmail}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground flex items-center gap-1">
                    <PhoneIcon size={14} /> Contact Phone
                  </Label>
                  <p className="font-medium">{application.contactPhone}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Financial Information */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <CurrencyCircleDollarIcon size={20} />
                Financial Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <Label className="text-muted-foreground">Proposed Capital</Label>
                <p className="text-2xl font-bold">{formatCurrency(application.proposedCapital)}</p>
              </div>
              <Separator />
              <div>
                <Label className="text-muted-foreground">Business Plan Summary</Label>
                <p className="mt-2 whitespace-pre-wrap">{application.businessPlan}</p>
              </div>
            </CardContent>
          </Card>

          {/* Review Information (if reviewed) */}
          {application.reviewerId && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <MagnifyingGlassIcon size={20} />
                  Review Information
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 sm:grid-cols-2">
                  <div>
                    <Label className="text-muted-foreground">Reviewer</Label>
                    <p className="font-medium">{application.reviewerName}</p>
                    <p className="text-sm text-muted-foreground">{application.reviewerEmail}</p>
                  </div>
                  {application.reviewRecommendation && (
                    <div>
                      <Label className="text-muted-foreground">Recommendation</Label>
                      <Badge 
                        variant={application.reviewRecommendation === 'approve' ? 'default' : 'destructive'}
                        className={application.reviewRecommendation === 'approve' ? 'bg-green-500' : ''}
                      >
                        {application.reviewRecommendation === 'approve' ? 'Recommend Approval' : 'Recommend Rejection'}
                      </Badge>
                    </div>
                  )}
                </div>
                {application.reviewNotes && (
                  <div>
                    <Label className="text-muted-foreground">Review Notes</Label>
                    <p className="mt-2 whitespace-pre-wrap">{application.reviewNotes}</p>
                  </div>
                )}
                {application.reviewedAt && (
                  <div>
                    <Label className="text-muted-foreground">Reviewed On</Label>
                    <p>{format(new Date(application.reviewedAt), 'PPP pp')}</p>
                  </div>
                )}
              </CardContent>
            </Card>
          )}

          {/* Documents */}
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle className="flex items-center gap-2">
                  <FileTextIcon size={20} />
                  Documents
                </CardTitle>
                <CardDescription>Supporting documents for this application</CardDescription>
              </div>
              {canUploadDocuments && (
                <Button variant="outline" size="sm" onClick={() => setShowUploadDialog(true)} className="gap-2">
                  <UploadIcon size={16} />
                  Upload
                </Button>
              )}
            </CardHeader>
            <CardContent>
              {documents.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  <FileTextIcon className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p>No documents uploaded yet</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {documents.map((doc) => (
                    <div
                      key={doc.id}
                      className="flex items-center justify-between rounded-lg border p-3"
                    >
                      <div className="flex items-center gap-3">
                        <FileTextIcon className="h-8 w-8 text-muted-foreground" />
                        <div>
                          <p className="font-medium">{doc.name}</p>
                          <p className="text-xs text-muted-foreground">
                            {formatFileSize(doc.size)} - v{doc.version} - Uploaded {formatDistanceToNow(new Date(doc.uploadedAt), { addSuffix: true })}
                          </p>
                        </div>
                      </div>
                      <Button variant="ghost" size="sm" className="gap-2">
                        <EyeIcon size={16} />
                        View
                      </Button>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          {/* Applicant Info */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <UserIcon size={20} />
                Applicant
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <p className="font-medium">{application.applicantName}</p>
              <p className="text-sm text-muted-foreground">{application.applicantEmail}</p>
            </CardContent>
          </Card>

          {/* Timeline */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <ClockIcon size={20} />
                Timeline
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">Created</span>
                <span>{format(new Date(application.createdAt), 'PP')}</span>
              </div>
              {application.submittedAt && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Submitted</span>
                  <span>{format(new Date(application.submittedAt), 'PP')}</span>
                </div>
              )}
              {application.reviewedAt && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Reviewed</span>
                  <span>{format(new Date(application.reviewedAt), 'PP')}</span>
                </div>
              )}
              {application.decidedAt && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Decision</span>
                  <span>{format(new Date(application.decidedAt), 'PP')}</span>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Audit Log Preview */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <ClockCounterClockwiseIcon size={20} />
                Recent Activity
              </CardTitle>
            </CardHeader>
            <CardContent>
              {auditLog.length === 0 ? (
                <p className="text-sm text-muted-foreground">No activity recorded</p>
              ) : (
                <div className="space-y-3">
                  {auditLog.slice(0, 5).map((entry) => (
                    <div key={entry.id} className="text-sm">
                      <p className="font-medium capitalize">
                        {entry.action.replace(/_/g, ' ')}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        by {entry.userName} - {formatDistanceToNow(new Date(entry.timestamp), { addSuffix: true })}
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Complete Review Dialog */}
      <Dialog open={showReviewDialog} onOpenChange={setShowReviewDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Complete Review</DialogTitle>
            <DialogDescription>
              Provide your review notes and recommendation for this application.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {actionError && (
              <Alert variant="destructive">
                <AlertDescription>{actionError}</AlertDescription>
              </Alert>
            )}
            <div className="space-y-2">
              <Label>Recommendation *</Label>
              <Select value={recommendation} onValueChange={(v) => setRecommendation(v as 'approve' | 'reject')}>
                <SelectTrigger>
                  <SelectValue placeholder="Select recommendation" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="approve">Recommend Approval</SelectItem>
                  <SelectItem value="reject">Recommend Rejection</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Review Notes</Label>
              <Textarea
                placeholder="Enter your review notes..."
                value={reviewNotes}
                onChange={(e) => setReviewNotes(e.target.value)}
                rows={4}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowReviewDialog(false)}>
              Cancel
            </Button>
            <Button
              onClick={() => performAction('complete_review', { notes: reviewNotes, recommendation })}
              disabled={!recommendation || isActionLoading}
            >
              {isActionLoading ? <Spinner className="h-4 w-4" /> : 'Submit Review'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Request Info Dialog */}
      <Dialog open={showRequestInfoDialog} onOpenChange={setShowRequestInfoDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Request Additional Information</DialogTitle>
            <DialogDescription>
              Specify what additional information or documents are needed from the applicant.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {actionError && (
              <Alert variant="destructive">
                <AlertDescription>{actionError}</AlertDescription>
              </Alert>
            )}
            <div className="space-y-2">
              <Label>Information Required *</Label>
              <Textarea
                placeholder="Describe what additional information is needed..."
                value={additionalInfoRequest}
                onChange={(e) => setAdditionalInfoRequest(e.target.value)}
                rows={4}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowRequestInfoDialog(false)}>
              Cancel
            </Button>
            <Button
              onClick={() => performAction('request_info', { notes: additionalInfoRequest })}
              disabled={!additionalInfoRequest || isActionLoading}
            >
              {isActionLoading ? <Spinner className="h-4 w-4" /> : 'Send Request'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Approval Dialog */}
      <Dialog open={showApprovalDialog} onOpenChange={setShowApprovalDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Approve Application</DialogTitle>
            <DialogDescription>
              This action is final and cannot be undone. The applicant will be notified of the approval.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {actionError && (
              <Alert variant="destructive">
                <AlertDescription>{actionError}</AlertDescription>
              </Alert>
            )}
            <div className="space-y-2">
              <Label>Approval Notes (Optional)</Label>
              <Textarea
                placeholder="Add any notes about this approval..."
                value={approvalNotes}
                onChange={(e) => setApprovalNotes(e.target.value)}
                rows={3}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowApprovalDialog(false)}>
              Cancel
            </Button>
            <Button
              onClick={() => performAction('approve', { notes: approvalNotes })}
              disabled={isActionLoading}
              className="bg-green-600 hover:bg-green-700"
            >
              {isActionLoading ? <Spinner className="h-4 w-4" /> : 'Confirm Approval'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Reject Dialog */}
      <Dialog open={showRejectDialog} onOpenChange={setShowRejectDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Reject Application</DialogTitle>
            <DialogDescription>
              This action is final and cannot be undone. The applicant will be notified of the rejection.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {actionError && (
              <Alert variant="destructive">
                <AlertDescription>{actionError}</AlertDescription>
              </Alert>
            )}
            <div className="space-y-2">
              <Label>Reason for Rejection *</Label>
              <Textarea
                placeholder="Provide the reason for rejecting this application..."
                value={rejectionReason}
                onChange={(e) => setRejectionReason(e.target.value)}
                rows={4}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowRejectDialog(false)}>
              Cancel
            </Button>
            <Button
              variant="destructive"
              onClick={() => performAction('reject', { reason: rejectionReason })}
              disabled={!rejectionReason || isActionLoading}
            >
              {isActionLoading ? <Spinner className="h-4 w-4" /> : 'Confirm Rejection'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Upload Document Dialog */}
      <Dialog open={showUploadDialog} onOpenChange={setShowUploadDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Upload Document</DialogTitle>
            <DialogDescription>
              Select a document to upload. Maximum file size is 5MB.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {actionError && (
              <Alert variant="destructive">
                <AlertDescription>{actionError}</AlertDescription>
              </Alert>
            )}
            <div className="space-y-2">
              <Label>Select File</Label>
              <input
                type="file"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) {
                    if (file.size > 5 * 1024 * 1024) {
                      setActionError('File size exceeds 5MB limit');
                      return;
                    }
                    setUploadFile({
                      name: file.name,
                      type: file.type,
                      size: file.size,
                    });
                    setActionError('');
                  }
                }}
                className="block w-full text-sm text-muted-foreground file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-medium file:bg-primary file:text-primary-foreground hover:file:bg-primary/90"
              />
              <p className="text-xs text-muted-foreground">
                Note: This is a simulated upload. File metadata will be stored but the actual file content is not saved.
              </p>
            </div>
            {uploadFile && (
              <div className="rounded-lg border p-3">
                <p className="font-medium">{uploadFile.name}</p>
                <p className="text-xs text-muted-foreground">
                  {uploadFile.type} - {formatFileSize(uploadFile.size)}
                </p>
              </div>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => { setShowUploadDialog(false); setUploadFile(null); }}>
              Cancel
            </Button>
            <Button
              onClick={uploadDocument}
              disabled={!uploadFile || isActionLoading}
            >
              {isActionLoading ? <Spinner className="h-4 w-4" /> : 'Upload'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
